     * Checks if this node ends with a trailing lambda (a CALL_EXPRESSION with a FUNCTION_LITERAL).
     * Only returns true if the lambda is at the very end of this node's tree.
     */
    private fun ASTNode.endsWithTrailingLambda(): Boolean {
        // Navigate from the last leaf up to find if we're inside a CALL_EXPRESSION with a lambda
        val lastLeaf = lastChildLeafOrSelf()

        // Check if the last leaf is part of a FUNCTION_LITERAL
        val functionLiteral = lastLeaf
            .parents()
            .takeWhile { it != this }
            .firstOrNull { it.elementType == FUNCTION_LITERAL }

        if (functionLiteral == null) {
            return false
        }

        // Check if this FUNCTION_LITERAL is a direct child of a CALL_EXPRESSION
        val callExpression = functionLiteral.treeParent
        return callExpression?.elementType == CALL_EXPRESSION &&
            callExpression.parents().takeWhile { it != this }.any { it == callExpression.treeParent }
    }"}

