/**
 * Test for indentation of lambdas in chained method calls.
 * This addresses the issue where lambdas at the end of chained calls
 * (DOT_QUALIFIED_EXPRESSION or SAFE_ACCESS_EXPRESSION) were incorrectly indented.
 */
class IndentationRuleChainedLambdaTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a chained call with runCatching and let lambda then indent correctly`() {
        val code =
            """
            class TestClass {
                private fun test(): Boolean? =
                    runCatching { true }
                        .getOrNull()?.let { result ->
                            !result
                        }
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a chained call with safe access and lambda then indent correctly`() {
        val code =
            """
            fun process(value: String?): Int? =
                value
                    ?.trim()
                    ?.let { trimmed ->
                        trimmed.length
                    }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a dot chained call with lambda then indent correctly`() {
        val code =
            """
            fun calculate(): Int =
                listOf(1, 2, 3)
                    .filter { it > 1 }
                    .map { value ->
                        value * 2
                    }
                    .sum()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a complex chain with multiple lambdas then indent correctly`() {
        val code =
            """
            fun process(): String? =
                getData()
                    ?.filter { item ->
                        item.isValid()
                    }
                    ?.firstOrNull()
                    ?.let { first ->
                        processItem(first)
                    }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

